sp_widget.client_script:
api.controller = function() {
  var c = this;

  c.searching = false;
  c.reference = '';

  c.search = function() {
    if (!c.reference || !c.reference.trim()) return;
    c.searching = true;
    c.server.get({
      action: 'search',
      reference: c.reference.trim()
    }).then(function(r) {
      c.data = r.data;
      c.searching = false;
    }, function() {
      c.searching = false;
      c.data.searched = true;
      c.data.found = false;
      c.data.message = 'A network error occurred. Please try again.';
    });
  };

  c.searchOnEnter = function(event) {
    if (event.keyCode === 13) {
      c.search();
    }
  };

  c.isStageActive = function(stageKey) {
    if (!c.data.record) return false;
    var stageOrder = { submitted: 0, shipping_label_sent: 0, device_received: 1, in_processing: 2, complete: 3 };
    var currentIndex = stageOrder[c.data.record.status];
    var stageIndex = stageOrder[stageKey];
    if (currentIndex === undefined || stageIndex === undefined) return false;
    return stageIndex <= currentIndex;
  };

  c.isCurrentStage = function(stageKey) {
    if (!c.data.record) return false;
    var statusToStage = {
      submitted: 'submitted',
      shipping_label_sent: 'submitted',
      device_received: 'device_received',
      in_processing: 'in_processing',
      complete: 'complete'
    };
    return statusToStage[c.data.record.status] === stageKey;
  };

  c.reset = function() {
    c.reference = '';
    c.data.searched = false;
    c.data.found = false;
    c.data.record = null;
    c.data.message = '';
  };
};

sp_widget.css:
/* Page header */
.cb-page-header {
  margin-bottom: 32px;
}
.cb-page-title {
  font-size: 26px;
  font-weight: 700;
  color: $text-color;
  margin: 0 0 8px;
}
.cb-title-icon {
  color: $brand-primary;
  margin-right: 8px;
  font-size: 26px;
}
.cb-page-subtitle {
  font-size: $font-size-base;
  max-width: 480px;
  margin: 0 auto;
}

/* Search bar */
.cb-search-bar {
  max-width: 520px;
  margin: 0 auto 24px;
}
.sp-input {
  height: $input-height-base;
  border: 1px solid $border-tertiary;
  border-radius: $border-radius-base;
  padding: 0 12px;
  font-size: $font-size-base;
  color: $text-color;
  background: $background-primary;
  transition: border-color 0.15s, box-shadow 0.15s;
  &:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
    outline: none;
  }
}
.cb-search-input {
  height: 48px;
  font-size: $font-size-large;
  letter-spacing: 0.03em;
}
.sp-btn-primary {
  height: 48px;
  padding: 0 20px;
  border-radius: $border-radius-base;
  font-size: $font-size-base;
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  transition: background 0.15s, box-shadow 0.15s;
  cursor: pointer;
  border: none;
  background: $brand-primary;
  color: $btn-primary-color;
  &:hover:not(:disabled) {
    background: $brand-primary-dark;
    box-shadow: 0 2px 8px rgba($brand-primary, 0.3);
    color: $btn-primary-color;
  }
  &:disabled {
    opacity: 0.55;
    cursor: not-allowed;
  }
}

/* Not found */
.cb-not-found {
  max-width: 520px;
  margin: 0 auto;
}

/* Result panel */
.cb-result-panel {
  border: 1px solid $border-tertiary;
  border-radius: $border-radius-large;
  box-shadow: 0 1px 4px rgba($text-color, 0.07);
  overflow: hidden;
}
.cb-result-header {
  background: $background-primary;
  border-bottom: 1px solid $border-tertiary;
  padding: 16px 24px;
}
.cb-result-ref {
  font-size: 22px;
  font-weight: 700;
  color: $brand-primary;
  margin: 0;
}

/* Details row */
.cb-details-row {
  margin-bottom: 32px;
}
.cb-detail-item {
  padding: 12px 0;
}
.cb-detail-label {
  display: block;
  font-size: 12px;
  font-weight: 600;
  color: $text-muted;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  margin-bottom: 4px;
}
.cb-detail-value {
  display: block;
  font-size: $font-size-base;
  font-weight: 500;
  color: $text-color;
}

/* Step indicator */
.cb-stepper {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  margin-bottom: 32px;
  padding: 0 16px;
}
.cb-step {
  display: flex;
  flex-direction: column;
  align-items: center;
  position: relative;
  flex: 1;
  min-width: 0;
}
.cb-step-dot {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: $background-tertiary;
  color: $text-muted;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: $font-size-base;
  font-weight: 600;
  position: relative;
  z-index: 1;
  transition: background 0.3s, color 0.3s;
  flex-shrink: 0;
}
.cb-step-active .cb-step-dot {
  background: $brand-primary;
  color: $btn-primary-color;
}
.cb-step-current .cb-step-dot {
  box-shadow: 0 0 0 4px rgba($brand-primary, 0.25);
}
.cb-step-connector {
  position: absolute;
  top: 20px;
  left: calc(50% + 20px);
  width: calc(100% - 40px);
  height: 3px;
  background: $background-tertiary;
  z-index: 0;
}
.cb-step-active .cb-step-connector {
  background: $brand-primary;
}
.cb-step-label {
  margin-top: 8px;
  font-size: 12px;
  font-weight: 500;
  color: $text-muted;
  text-align: center;
  line-height: 1.3;
}
.cb-step-active .cb-step-label {
  color: $brand-primary;
  font-weight: 600;
}

/* Status message */
.cb-status-message {
  background: rgba($brand-primary, 0.08);
  border: 1px solid rgba($brand-primary, 0.2);
  border-radius: $border-radius-base;
  padding: 16px 24px;
  font-size: $font-size-base;
  color: $text-color;
  text-align: center;
  .glyphicon {
    color: $brand-primary;
    margin-right: 8px;
  }
}

/* Spinner */
@keyframes sp-spin {
  to { transform: rotate(360deg); }
}
.sp-spin {
  animation: sp-spin 0.8s linear infinite;
}

/* Responsive */
@media (max-width: 480px) {
  .cb-step-label {
    font-size: 11px;
  }
  .cb-step-dot {
    width: 32px;
    height: 32px;
    font-size: 12px;
  }
  .cb-step-connector {
    top: 16px;
    left: calc(50% + 16px);
    width: calc(100% - 32px);
  }
}

sp_widget.script:
(function() {
  data.searched = false;
  data.found = false;
  data.record = null;
  data.message = '';

  // The four stages shown on the step indicator
  data.stages = [
    { key: 'submitted', label: 'Submitted' },
    { key: 'device_received', label: 'Device Received' },
    { key: 'in_processing', label: 'In Processing' },
    { key: 'complete', label: 'Complete' }
  ];

  // Status-to-message mapping
  data.statusMessages = {
    submitted: 'We have your request. Check your email for your shipping label.',
    shipping_label_sent: 'We have your request. Check your email for your shipping label.',
    device_received: 'Your device has arrived safely with us.',
    in_processing: 'We are assessing your device. Your reward will be issued soon.',
    complete: 'All done. Check your email for your reward details.'
  };

  if (input && input.action === 'search') {
    data.searched = true;

    try {
      var ref = (input.reference || '').trim().toUpperCase();
      if (!ref) {
        data.found = false;
        data.message = 'Please enter a return reference number.';
        return;
      }

      var gr = new GlideRecord('x_1845356_circle_0_return_request');
      gr.addQuery('return_reference', ref);
      gr.setLimit(1);
      gr.query();

      if (gr.next()) {
        data.found = true;
        data.record = {
          return_reference: gr.getValue('return_reference'),
          device_model: gr.getValue('device_model'),
          submission_date: gr.getDisplayValue('submission_date'),
          status: gr.getValue('status'),
          status_display: gr.getDisplayValue('status')
        };
        data.message = data.statusMessages[data.record.status] || '';
      } else {
        data.found = false;
        data.message = 'We could not find that reference. Please check and try again.';
      }
    } catch (e) {
      gs.error('CircleBack track widget error: ' + e.message);
      data.found = false;
      data.message = 'An error occurred while searching. Please try again later.';
    }
    return;
  }
})();
